import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';

function ListaClientes() {
  const [clientes, setClientes] = useState([]);

  useEffect(() => {
    carregarClientes();
  }, []);

  const carregarClientes = async () => {
    try {
      const response = await api.listarClientes();
      setClientes(response.data);
    } catch (error) {
      alert('Erro ao carregar clientes: ' + error.message);
    }
  };

  const handleExcluir = async (id) => {
    if (window.confirm('Tem certeza que deseja excluir este cliente?')) {
      try {
        await api.deletarCliente(id);
        carregarClientes();
      } catch (error) {
        alert('Erro ao excluir cliente: ' + error.message);
      }
    }
  };

  return (
    <div>
      <h1>Clientes</h1>
      <Link to="/clientes/novo">Adicionar Cliente</Link>
      
      <table>
        <thead>
          <tr>
            <th>Nome</th>
            <th>CPF/CNPJ</th>
            <th>Celular</th>
            <th>Ações</th>
          </tr>
        </thead>
        <tbody>
          {clientes.map(cliente => (
            <tr key={cliente.id_cliente}>
              <td>{cliente.nome}</td>
              <td>{cliente.cpf_cnpj_formatado}</td>
              <td>{cliente.celular_formatado}</td>
              <td>
                <Link to={`/clientes/editar/${cliente.id_cliente}`}>Editar</Link>
                <button onClick={() => handleExcluir(cliente.id_cliente)}>Excluir</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default ListaClientes;
